import React from 'react';
import StatusCards from '../components/StatusCards';
import ChargerList from '../components/ChargerList';
import { ChargerStatus } from '../types';

const mockChargers: ChargerStatus[] = [
  {
    id: 'CH-001',
    name: 'Downtown Hub A1',
    status: 'charging',
    voltage: 402,
    current: 118,
    power: 47.4,
    temperature: 41,
    lastUpdated: new Date('2026-04-13T15:45:00'),
  },
  {
    id: 'CH-002',
    name: 'Downtown Hub A2',
    status: 'online',
    voltage: 398,
    current: 0,
    power: 0,
    temperature: 33,
    lastUpdated: new Date('2026-04-13T15:44:30'),
  },
  {
    id: 'CH-003',
    name: 'Airport Lot B4',
    status: 'fault',
    voltage: 0,
    current: 0,
    power: 0,
    temperature: 52,
    errorCode: 'OVT-14',
    lastUpdated: new Date('2026-04-13T15:43:10'),
  },
  {
    id: 'CH-004',
    name: 'Mall Station C2',
    status: 'offline',
    voltage: 0,
    current: 0,
    power: 0,
    temperature: 28,
    lastUpdated: new Date('2026-04-13T15:40:22'),
  },
];

const Dashboard: React.FC = () => {
  return (
    <section className="dashboard">
      <h1>Dashboard</h1>
      <StatusCards chargers={mockChargers} />
      <ChargerList chargers={mockChargers} />
    </section>
  );
};

export default Dashboard;
